package serviceimpl

import (
	"context"
	"testing"
	"time"
)

func TestExecuteNativeRemovesBenchmarkPresetPlanning(t *testing.T) {
	// Test that PlanningMode flows only from req.PlanningMode, not from ToolPreset.
	// Even when ToolPreset=="benchmark", PlanningMode should not be implicitly set.

	// Case 1: ToolPreset="benchmark", PlanningMode=false should result in false
	result1 := RunNative(context.Background(), NativeRequest{
		Prompt:       "test",
		Model:        "test-model",
		Provider:     "test-provider",
		Harness:      "test",
		ToolPreset:   "benchmark",
		PlanningMode: false,
		Decision: NativeDecision{
			Harness:  "test",
			Provider: "test-provider",
			Model:    "test-model",
		},
		Started: time.Now(),
	})

	if result1.Final.PlanningMode != false {
		t.Errorf("ToolPreset=benchmark, PlanningMode=false: got PlanningMode=%v, want false", result1.Final.PlanningMode)
	}

	// Case 2: ToolPreset="benchmark", PlanningMode=true should result in true
	result2 := RunNative(context.Background(), NativeRequest{
		Prompt:       "test",
		Model:        "test-model",
		Provider:     "test-provider",
		Harness:      "test",
		ToolPreset:   "benchmark",
		PlanningMode: true,
		Decision: NativeDecision{
			Harness:  "test",
			Provider: "test-provider",
			Model:    "test-model",
		},
		Started: time.Now(),
	})

	if result2.Final.PlanningMode != true {
		t.Errorf("ToolPreset=benchmark, PlanningMode=true: got PlanningMode=%v, want true", result2.Final.PlanningMode)
	}

	// Case 3: ToolPreset="other", PlanningMode=true should result in true
	result3 := RunNative(context.Background(), NativeRequest{
		Prompt:       "test",
		Model:        "test-model",
		Provider:     "test-provider",
		Harness:      "test",
		ToolPreset:   "other",
		PlanningMode: true,
		Decision: NativeDecision{
			Harness:  "test",
			Provider: "test-provider",
			Model:    "test-model",
		},
		Started: time.Now(),
	})

	if result3.Final.PlanningMode != true {
		t.Errorf("ToolPreset=other, PlanningMode=true: got PlanningMode=%v, want true", result3.Final.PlanningMode)
	}
}

